P loadTextGPS     B
D loadTextGPS     PI
D   start                        3  0 value
D*----------------------------------------------------------------
  Chain(N) KEYGPS2 HSGPSPR;
  DOW Not %EoF(HSGPSPF);
      If GPS150 = %Dec(G7306A:2:0) And
         GPS020 = *Blanks And GPS040 = 'TXT';
         If %Subst(GPS080:1:1) <> '+';
            TEXT = GPS080;
            ZLT += 1;
            If ZLT > start;
               Write HS1212ST;
            EndIf;
         EndIf;
      EndIf;
      ReadE(N) KEYGPS2 HSGPSPR;
  EndDo;
P                 E
